	(6, 'Hiệp Sĩ Từ Vựng', 'Hãy cố gắng đạt 2000 KN để nhận huy hiệu Hiệp Sĩ Từ Vựng!', 2000, 'https://res.cloudinary.com/dcz6avkds/image/upload/v1780020524/img_file/badge/dqyk9ky4iltvjoytecta.png', 'active'),
	(7, 'Bậc Thầy Giao Tiếp', 'Hãy cố gắng đạt 3500 KN để nhận huy hiệu Bậc Thầy Giao Tiếp!', 3500, 'https://res.cloudinary.com/dcz6avkds/image/upload/v1780020536/img_file/badge/vmtqy6wfsry7drupsc1s.png', 'active'),
