INSERT INTO `chatbot_rule` (`id`, `bot_response`, `created_at`, `is_active`, `keywords`, `priority`, `updated_at`, `category_id`, `rule_name`) VALUES
	(1, 'Xin chào! Mình là trợ lý hỗ trợ tự động của Lion. Bạn cần giúp đỡ gì không? Nếu câu hỏi của bạn phức tạp hơn, mình sẽ chuyển cho admin hỗ trợ nhé!', '2026-05-14 21:43:17.000000', b'1', 'xin chào|hello|hi|chào|hey', 10, '2026-05-15 01:44:36.000000', NULL, 'Chào hỏi'),
	(2, 'Không có gì! Nếu bạn cần thêm hỗ trợ, đừng ngại nhắn tin nhé. Chúc bạn học tốt!', '2026-05-14 21:43:18.000000', b'0', 'cảm ơn|thank|thanks|cám ơn', 10, '2026-05-15 01:44:37.000000', NULL, 'Cảm ơn'),
	(3, 'Đội ngũ hỗ trợ của Lion làm việc từ 8:00 - 22:00 hàng ngày. Ngoài giờ này, bạn có thể để lại tin nhắn và admin sẽ phản hồi sớm nhất có thể!', '2026-05-14 21:43:17.000000', b'1', 'giờ làm việc|thời gian hỗ trợ|khi nào có admin|admin online', 8, '2026-05-14 21:43:37.000000', NULL, 'Giờ làm việc'),
	(4, 'Để đặt lại mật khẩu, bạn làm theo các bước sau:\n1. Vào trang đăng nhập\n2. Nhấn "Quên mật khẩu"\n3. Nhập email đã đăng ký\n4. Kiểm tra hộp thư và làm theo hướng dẫn\n\nNếu không nhận được email, hãy kiểm tra thư mục Spam nhé!', '2026-05-14 21:43:24.000000', b'1', 'quên mật khẩu|forgot password|reset password|đổi mật khẩu|không đăng nhập được', 20, '2026-05-15 01:33:31.000000', 2, 'Quên mật khẩu'),
	(5, 'Hiện tại hệ thống chưa hỗ trợ tự đổi email. Vui lòng liên hệ admin để được hỗ trợ thay đổi email tài khoản.', '2026-05-14 21:43:18.000000', b'1', 'đổi email|thay email|cập nhật email', 15, '2026-05-14 21:43:35.000000', 2, 'Đổi email'),
	(6, 'Để xóa tài khoản, bạn cần liên hệ trực tiếp với admin. Lưu ý rằng toàn bộ dữ liệu học tập sẽ bị xóa vĩnh viễn và không thể khôi phục.', '2026-05-14 21:43:19.000000', b'1', 'xóa tài khoản|delete account|hủy tài khoản', 15, '2026-05-14 21:43:37.000000', 2, 'Xóa tài khoản'),
	(7, 'Lion hỗ trợ đăng nhập bằng Google và Facebook. Nhấn nút tương ứng trên trang đăng nhập. Nếu gặp lỗi, hãy thử xóa cache trình duyệt và thử lại nhé!', '2026-05-14 21:43:19.000000', b'1', 'đăng nhập google|login google|đăng nhập facebook|social login', 15, '2026-05-14 21:43:34.000000', 2, 'Đăng nhập mạng xã hội'),
	(8, 'Để bắt đầu học trên Lion:\n1. Hoàn thành bài kiểm tra đầu vào để xác định trình độ\n2. Hệ thống sẽ gợi ý lộ trình học phù hợp\n3. Học theo thứ tự các bài trong Skill Tree\n4. Hoàn thành bài tập để mở khóa bài tiếp theo\n\nChúc bạn học vui! 🦁', '2026-05-14 21:43:25.000000', b'1', 'bắt đầu|bắt đầu học|học như thế nào|học ở đâu|hướng dẫn|tutorial', 20, '2026-05-28 15:37:23.000000', 1, 'Hướng dẫn bắt đầu'),
	(9, 'Lion sử dụng khung tham chiếu CEFR với 3 cấp độ: Beginner (A1-A2), Intermediate (B1-B2), Advanced (C1-C2). Làm bài kiểm tra đầu vào để biết trình độ hiện tại của bạn nhé!', '2026-05-14 21:43:20.000000', b'1', 'trình độ|level|cefr|a1|a2|b1|b2|c1|c2', 15, '2026-05-14 21:43:34.000000', 1, 'Trình độ CEFR'),
	(10, 'Bài kiểm tra đầu vào giúp xác định trình độ tiếng Anh của bạn. Vào mục "Kiểm tra đầu vào" trên menu để bắt đầu. Bài test khoảng 20-30 phút và bao gồm các kỹ năng nghe, đọc, từ vựng.', '2026-05-14 21:43:21.000000', b'1', 'kiểm tra đầu vào|placement test|bài test|xếp lớp', 15, '2026-05-14 21:43:33.000000', 1, 'Kiểm tra đầu vào'),
	(11, 'Bài học bị khóa có nghĩa là bạn cần hoàn thành bài trước đó trước. Hãy hoàn thành tất cả bài tập trong node hiện tại để mở khóa bài tiếp theo nhé!', '2026-05-14 21:43:26.000000', b'1', 'bài học|lesson|không mở được bài|bài bị khóa|unlock', 20, '2026-05-14 21:43:29.000000', 3, 'Bài học bị khóa'),
	(12, 'Điểm XP được tích lũy khi bạn hoàn thành bài học và bài tập. Điểm cao hơn giúp bạn leo hạng trên bảng xếp hạng. Mỗi câu trả lời đúng = 10 XP!', '2026-05-14 21:43:21.000000', b'1', 'điểm|score|xp|kinh nghiệm|tích điểm', 15, '2026-05-14 21:43:32.000000', 3, 'Điểm XP'),
	(13, 'Streak là số ngày học liên tiếp của bạn. Học ít nhất 1 bài mỗi ngày để duy trì streak. Streak cao giúp bạn nhận thêm XP bonus!', '2026-05-14 21:43:22.000000', b'1', 'streak|chuỗi ngày|ngày liên tiếp|duy trì streak', 15, '2026-05-14 21:43:32.000000', 3, 'Streak học tập'),
	(14, 'Bạn đang gặp lỗi kỹ thuật? Hãy thử:\n1. Tải lại trang (F5 hoặc Ctrl+R)\n2. Xóa cache trình duyệt\n3. Thử trình duyệt khác (Chrome, Firefox)\n4. Kiểm tra kết nối internet\n\nNếu vẫn lỗi, hãy mô tả chi tiết để admin hỗ trợ nhé!', '2026-05-14 21:43:27.000000', b'1', 'lỗi|bug|không hoạt động|crash|trắng màn hình|không load', 20, '2026-05-14 21:43:28.000000', 4, 'Lỗi kỹ thuật'),
	(15, 'Nếu không nghe được âm thanh:\n1. Kiểm tra loa/tai nghe đã cắm chưa\n2. Kiểm tra âm lượng hệ thống\n3. Cho phép trình duyệt truy cập microphone (nếu cần)\n4. Thử tải lại trang\n\nVẫn không được? Admin sẽ hỗ trợ bạn!', '2026-05-14 21:43:24.000000', b'1', 'âm thanh|audio|không nghe được|loa|microphone|mic', 15, '2026-05-14 21:43:31.000000', 4, 'Vấn đề âm thanh'),
	(16, 'Nếu ứng dụng chạy chậm:\n1. Kiểm tra tốc độ internet\n2. Đóng các tab/ứng dụng không cần thiết\n3. Xóa cache trình duyệt\n4. Thử vào lúc khác (có thể server đang bận)\n\nNếu vẫn chậm, hãy báo cho admin biết nhé!', '2026-05-14 21:43:23.000000', b'1', 'chậm|lag|loading|tải chậm|không phản hồi', 15, '2026-05-14 21:43:30.000000', 4, 'Ứng dụng chạy chậm');
