INSERT INTO `faq` (`id`, `question`, `answer`, `display_order`, `status`, `created_at`, `updated_at`) VALUES
	(1, 'Tôi nên bắt đầu từ đâu nếu mới học lại tiếng Anh?', 'Hãy bắt đầu bằng bài kiểm tra trình độ và lộ trình cơ bản.\nSau đó học 15-20 phút mỗi ngày.', 1, 'INACTIVE', '2026-06-04 17:28:28', '2026-06-04 11:29:37'),
	(2, 'Tôi có cần học mỗi ngày không?', 'Không bắt buộc nhưng nên học mỗi ngày để duy trì thói quen.\nChỉ cần 10-20 phút mỗi ngày là đã hiệu quả.', 2, 'ACTIVE', '2026-06-04 17:28:28', '2026-06-04 17:28:28'),
	(3, 'Học bao lâu thì có tiến bộ?', 'Tùy vào sự kiên trì của bạn.\nNếu học đều mỗi ngày, bạn sẽ thấy tiến bộ sau vài tuần.', 3, 'ACTIVE', '2026-06-04 17:28:28', '2026-06-04 17:28:28'),
	(4, 'Tôi quên mật khẩu thì phải làm sao?', 'Bạn hãy chọn "Quên mật khẩu" ở màn hình đăng nhập.\nSau đó làm theo hướng dẫn để đặt lại mật khẩu.', 4, 'ACTIVE', '2026-06-04 17:28:28', '2026-06-04 17:28:28'),
	(5, 'Tôi có thể đổi thông tin cá nhân không?', 'Có, bạn có thể chỉnh sửa thông tin trong phần hồ sơ cá nhân.\nBao gồm tên, avatar và các thông tin khác.', 5, 'ACTIVE', '2026-06-04 17:28:28', '2026-06-04 17:28:28'),
	(6, 'Tôi có thể đăng nhập trên nhiều thiết bị không?', 'Có, bạn có thể đăng nhập trên cả điện thoại và máy tính.\nDữ liệu học tập sẽ được đồng bộ.', 6, 'ACTIVE', '2026-06-04 17:28:28', '2026-06-04 17:28:28'),
	(7, 'Tôi học sai nhiều có sao không?', 'Không sao, sai là một phần của việc học.\nHệ thống sẽ giúp bạn ôn lại các câu sai.', 7, 'ACTIVE', '2026-06-04 17:28:28', '2026-06-04 17:28:28'),
	(8, 'Tôi có thể học lại bài cũ không?', 'Có, bạn có thể học lại bất kỳ bài nào đã hoàn thành.\nViệc ôn lại giúp bạn nhớ lâu hơn.', 8, 'ACTIVE', '2026-06-04 17:28:28', '2026-06-04 17:28:28'),
	(9, 'Làm sao để tăng level nhanh hơn?', 'Hoàn thành bài học mỗi ngày và giữ streak.\nLàm thêm bài luyện tập để nhận thêm XP.', 9, 'ACTIVE', '2026-06-04 17:28:28', '2026-06-04 17:28:28'),
	(10, 'Nếu bài học không tải được thì tôi nên làm gì?', 'Hãy tải lại trang hoặc kiểm tra kết nối mạng.\nNếu vẫn lỗi, hãy liên hệ hỗ trợ.', 10, 'ACTIVE', '2026-06-04 17:28:28', '2026-06-04 17:28:28'),
	(11, 'Ứng dụng bị lag hoặc chậm thì sao?', 'Hãy thử tải lại trang hoặc đóng các tab không cần thiết.\nKiểm tra lại kết nối Internet để đảm bảo ổn định.', 11, 'ACTIVE', '2026-06-04 17:28:28', '2026-06-04 17:28:28'),
	(12, 'Tôi không nghe được audio?', 'Hãy kiểm tra âm lượng thiết bị và trình duyệt.\nĐảm bảo bạn đã cho phép website sử dụng âm thanh.', 12, 'ACTIVE', '2026-06-04 17:28:28', '2026-06-04 17:28:28'),
	(13, 'Tôi có thể góp ý hoặc báo lỗi không?', 'Có, bạn có thể gửi góp ý qua form liên hệ.\nChúng tôi luôn sẵn sàng lắng nghe và cải thiện.', 13, 'ACTIVE', '2026-06-04 17:28:28', '2026-06-04 17:28:28'),
	(14, 'Ứng dụng có miễn phí không?', 'Phiên bản cơ bản là miễn phí.\nMột số tính năng nâng cao có thể yêu cầu nâng cấp.', 14, 'ACTIVE', '2026-06-04 17:28:28', '2026-06-04 17:28:28'),
	(15, 'Tôi có thể học offline không?', 'Hiện tại cần kết nối Internet để học.\nChúng tôi sẽ cập nhật tính năng offline trong tương lai.', 15, 'ACTIVE', '2026-06-04 17:28:28', '2026-06-04 17:28:28');
