INSERT INTO `user_level_question_snapshot` (`id`, `created_at`, `level_id`, `payload_json`, `updated_at`, `user_id`) VALUES
	(1, '2026-04-11 12:55:40.000000', 1, '[{"treeId":1,"levelId":1,"nodes":[{"nodeId":1,"title":"Vocabulary","nodeType":"VOCAB","questions":[{"id":27,"mongoQuestionId":"69c8f2ea1f0f44d8052a28ac","questionText":"Thomas Edison, ............................ was American, invented many things, including the light bulb.","options":["which","who","that","what"],"correctAnswer":"who","questionType":"VOCAB","audioUrl":""},{"id":147,"mongoQuestionId":"69c8f2f01f0f44d8052a2924","questionText":"Wear your ............ if you don\'t want to get water in your eyes.","options":["shuttlecock","helmet","goggles"],"correctAnswer":"goggles","questionType":"VOCAB","audioUrl":""},{"id":15,"mongoQuestionId":"69c8f2e91f0f44d8052a28a0","questionText":"We should all recycle ............................ so that it can be used again.","options":["paper","a paper"],"correctAnswer":"paper","questionType":"VOCAB","audioUrl":""},{"id":86,"mongoQuestionId":"69c8f2ed1f0f44d8052a28e7","questionText":"The children at the local primary school are working on a ............ related to the environment.","options":["thesis","seminar","tutorial","project"],"correctAnswer":"project","questionType":"VOCAB","audioUrl":""},{"id":114,"mongoQuestionId":"69c8f2ee1f0f44d8052a2903","questionText":"I think I forgot to ...... the printer on.","options":["open","make","switch"],"correctAnswer":"switch","questionType":"VOCAB","audioUrl":""},{"id":56,"mongoQuestionId":"69c8f2eb1f0f44d8052a28c9","questionText":"Spend a ............................ amount of just €20 and get a free digital clock!","options":["least","lowest","minimum","cheapest"],"correctAnswer":"minimum","questionType":"VOCAB","audioUrl":""},{"id":138,"mongoQuestionId":"69c8f2f01f0f44d8052a291b","questionText":"You shouldn\'t ............ meals. It\'s bad for your health.","options":["eat","stop","skip"],"correctAnswer":"skip","questionType":"VOCAB","audioUrl":""},{"id":158,"mongoQuestionId":"69c8f2f11f0f44d8052a292f","questionText":"Receptionists must be very ........... .","options":["physically fit","polite","imaginative"],"correctAnswer":"polite","questionType":"VOCAB","audioUrl":""},{"id":131,"mongoQuestionId":"69c8f2f01f0f44d8052a2914","questionText":"My uncle has ............ and goats on his farm.","options":["elephants","sheep","wolves"],"correctAnswer":"sheep","questionType":"VOCAB","audioUrl":""},{"id":153,"mongoQuestionId":"69c8f2f11f0f44d8052a292a","questionText":"She asked me ............ I wanted another piece of cake.","options":["if","where","that"],"correctAnswer":"if","questionType":"VOCAB","audioUrl":""}]},{"nodeId":2,"title":"Listening","nodeType":"LISTENING","questions":[{"id":2767,"mongoQuestionId":"69c8f42d1f0f44d8052a3398","questionText":"A: Fun party, isn\'t it? \\\\nB: Sure is. My _______(1) is Emma, by the way. \\\\nA: It\'s nice to meet you, Emma. I\'m Justin. \\\\nB: _______(2) to meet you, Justin. Do you _______(3) in L.A.? \\\\nA: No, I\'m from San Francisco. I\'m visiting my sister here. \\\\nB: Oh, I love San Francisco. I go there sometimes for work. \\\\nA: Really? Call me next time you\'re there. Let me give you my _______(4) number. \\\\nB: Okay, hope to see you again! _______(5) a _______(6) time here in L.A.!","options":[],"correctAnswer":"1:name | 2:Nice | 3:live | 4:phone | 5:Have | 6:great","questionType":"LISTENING","audioUrl":"https://res.cloudinary.com/dcz6avkds/video/upload/v1774445279/Tactics_for_Listening_Basic_CD1_06_doeerb.mp3"}]},{"nodeId":3,"title":"Speaking","nodeType":"SPEAKING","questions":[{"id":2923,"mongoQuestionId":"69c8f5771f0f44d8052a34b4","questionText":"1. server\\r\\n2. flight attendant\\r\\n3. teacher\\r\\n4. construction worker\\r\\n5. businessperson\\r\\n6. receptionist","options":[],"correctAnswer":"","questionType":"SPEAKING","audioUrl":"https://res.cloudinary.com/dcz6avkds/video/upload/v1774507144/Tactics_for_Listening_Basic_CD1_33_ieiizf.mp3"}]},{"nodeId":4,"title":"Matching","nodeType":"MATCHING","questions":[{"id":3099,"mongoQuestionId":"69c8f690