	(7, '2026-06-05 02:26:42.000000', 3, '[{"treeId":16,"levelId":3,"nodes":[{"nodeId":76,"title":"Vocabulary","nodeType":"VOCAB","questions":[{"id":1994,"mongoQuestionId":"69c8f34e1f0f44d8052a305b","questionText":"Elizabeth\'s so lucky! Last week she won a writing competition and this week she\'s won the lottery, two ……… one after the other!","questionType":"VOCAB","options":["windbags","windpipes","wind-breaks","windfalls"],"correctAnswer":"windfalls","audioUrl":""},{"id":1936,"mongoQuestionId":"69c8f34b1f0f44d8052a3021","questionText":"I work such long hours that I don\'t really have time for much of a ............................ life.","questionType":"VOCAB","options":["friendly","outgoing","social","free"],"correctAnswer":"social","audioUrl":""},{"id":1923,"mongoQuestionId":"69c8f34a1f0f44d8052a3014","questionText":"The new Arts Centre seems to have been ............................ construction for quite some time.","questionType":"VOCAB","options":["in","under","on","below"],"correctAnswer":"under","audioUrl":""},{"id":1970,"mongoQuestionId":"69c8f34d1f0f44d8052a3043","questionText":"It was ........... of Harry to arrive late and then try to dominate the meeting.","questionType":"VOCAB","options":["common","usual","ordinary","typical"],"correctAnswer":"typical","audioUrl":""},{"id":1946,"mongoQuestionId":"69c8f34b1f0f44d8052a302b","questionText":"Jake\'s completely round the ............................ , isn\'t he?","questionType":"VOCAB","options":["edge","side","corner","bend"],"correctAnswer":"bend","audioUrl":""},{"id":1980,"mongoQuestionId":"69c8f34d1f0f44d8052a304d","questionText":"James could no longer bear the ........... surroundings of the decrepit old house.","questionType":"VOCAB","options":["oppressive","pressing","domineering","overbearing"],"correctAnswer":"oppressive","audioUrl":""},{"id":1982,"mongoQuestionId":"69c8f34d1f0f44d8052a304f","questionText":"There are plans to build an ice ........... in our town.","questionType":"VOCAB","options":["ring","pool","rink","floor"],"correctAnswer":"rink","audioUrl":""},{"id":1922,"mongoQuestionId":"69c8f34a1f0f44d8052a3013","questionText":"Profits ............................ slightly next year, although we don\'t predict any job losses.","questionType":"VOCAB","options":["expect to fall","are expecting to fall","are expected falling","are expected to fall"],"correctAnswer":"are expected to fall","audioUrl":""},{"id":1943,"mongoQuestionId":"69c8f34b1f0f44d8052a3028","questionText":"Jerry loves snowboarding so much that it\'s almost like a drug ............................ .","questionType":"VOCAB","options":["passion","obsession","addiction","requirement"],"correctAnswer":"addiction","audioUrl":""},{"id":1937,"mongoQuestionId":"69c8f34b1f0f44d8052a3022","questionText":"Jim\'s a tough character and certainly won\'t let anyone push him ............................ .","questionType":"VOCAB","options":["up","off","around","through"],"correctAnswer":"around","audioUrl":""}]},{"nodeId":77,"title":"Listening","nodeType":"LISTENING","questions":[{"id":2865,"mongoQuestionId":"69c8f4321f0f44d8052a33fa","questionText":"He was born in: _______(1)\\\\nHe joined the ANC in: _______(2)\\\\n He became deputy president of the ANC in: _______(3)\\\\n He was sentenced to life in prison in: _______(4)\\\\n He was released from prison in: _______(5)\\\\n He became State President in: _______(6)\\\\n He retired in: _______(7)","questionType":"LISTENING","options":[],"correctAnswer":"1:1918 | 2:1942 | 3:1952 | 4:1964 | 5:1990 | 6:1994 | 7:1999","audioUrl":"https://res.cloudinary.com/dcz6avkds/video/upload/v1774495683/TFL_Expanding_CD3_24_pd0xhy.mp3"}]},{"nodeId":78,"title":"Speaking","nodeType":"SPEAKING","questions":[{"id":3004,"mongoQuestionId":"69c8f5901f0f44d8052a3505","questionText":"1. Would you hand me that book on the table?\\r\\n2. Could you pass the salt and pepper?\\r\\n3. What did you do?\\r\\n4. What would you do if you saw a famous actor?\\r\\n5. Could you sign your book f